// Configuration
const WORDS = [
  "DEVELOPPEMENT", "JAVASCRIPT", "PYTHON", "HTML", "CSS", 
  "ALGORITHME", "VARIABLE", "FONCTION", "BOUCLE", "TABLEAU",
  "OBJET", "CLASSE", "API", "DATABASE", "SERVER", "FRAMEWORK",
  "INTERFACE", "COMPILATION", "DEBUG", "SYNTAXE", "MODULE"
];
const MAX_ERRORS = 6;

// Variables du jeu
let chosenWord = '';
let guessedLetters = [];
let wrongGuesses = 0;
let gameActive = true;

// Éléments DOM
const wordDiv = document.getElementById('word');
const lettersDiv = document.getElementById('letters');
const statusDiv = document.getElementById('status');
const errorsSpan = document.getElementById('errors');
const foundSpan = document.getElementById('found');
const totalSpan = document.getElementById('total');
const restartBtn = document.getElementById('restart');

// Initialisation
initGame();

// Fonctions
function initGame() {
  // Choisir un mot aléatoire
  chosenWord = WORDS[Math.floor(Math.random() * WORDS.length)];
  guessedLetters = [];
  wrongGuesses = 0;
  gameActive = true;

  // Mettre à jour l'affichage
  renderWord();
  createLetterButtons();
  clearHangman();
  updateStatus();
  updateScore();

  // Mettre à jour le nombre total de lettres uniques
  const uniqueLetters = new Set(chosenWord.split('')).size;
  totalSpan.textContent = uniqueLetters;
}

function renderWord() {
  wordDiv.innerHTML = '';
  const uniqueLetters = new Set(chosenWord.split(''));

  for (let char of chosenWord) {
    const span = document.createElement('span');
    span.textContent = guessedLetters.includes(char) ? char : '_';
    span.style.color = guessedLetters.includes(char) ? '#333' : '#999';
    wordDiv.appendChild(span);
  }

  // Mettre à jour le nombre de lettres trouvées
  const found = [...uniqueLetters].filter(letter => guessedLetters.includes(letter)).length;
  foundSpan.textContent = found;
}

function createLetterButtons() {
  lettersDiv.innerHTML = '';

  for (let i = 65; i <= 90; i++) {
    const letter = String.fromCharCode(i);
    const btn = document.createElement('button');
    btn.textContent = letter;
    btn.dataset.letter = letter;
    btn.onclick = () => handleGuess(letter);
    lettersDiv.appendChild(btn);
  }
}

function handleGuess(letter) {
  if (!gameActive) return;

  // Vérifier si la lettre a déjà été devinée
  if (guessedLetters.includes(letter)) return;

  // Désactiver le bouton
  const button = document.querySelector(`button[data-letter="${letter}"]`);
  if (button) button.disabled = true;

  // Vérifier si la lettre est dans le mot
  if (chosenWord.includes(letter)) {
    guessedLetters.push(letter);
    button.classList.add('correct');
    renderWord();
    checkWin();
  } else {
    wrongGuesses++;
    button.classList.add('wrong');
    updateHangman();
    updateScore();
    checkLose();
  }
}

function updateHangman() {
  const parts = [
    document.querySelector('.head'),
    document.querySelector('.body'),
    document.querySelector('.arm-left'),
    document.querySelector('.arm-right'),
    document.querySelector('.leg-left'),
    document.querySelector('.leg-right')
  ];

  // Afficher les parties en fonction des erreurs
  parts.forEach((part, index) => {
    if (index < wrongGuesses) {
      part.style.opacity = '1';
    } else {
      part.style.opacity = '0';
    }
  });

  errorsSpan.textContent = wrongGuesses;
}

function clearHangman() {
  const parts = document.querySelectorAll('.gallows > div:not(.base):not(.pole):not(.top):not(.rope)');
  parts.forEach(part => {
    part.style.opacity = '0';
  });
  errorsSpan.textContent = '0';
}

function checkWin() {
  const uniqueLetters = new Set(chosenWord.split(''));
  const allFound = [...uniqueLetters].every(letter => guessedLetters.includes(letter));

  if (allFound) {
    gameActive = false;
    statusDiv.textContent = `🎉 Bravo ! Le mot était : ${chosenWord}`;
    statusDiv.className = 'win';
    disableAllButtons();
  }
}

function checkLose() {
  if (wrongGuesses >= MAX_ERRORS) {
    gameActive = false;
    statusDiv.textContent = `💀 Perdu ! Le mot était : ${chosenWord}`;
    statusDiv.className = 'lose';
    disableAllButtons();
  }
}

function disableAllButtons() {
  document.querySelectorAll('#letters button').forEach(btn => {
    btn.disabled = true;
  });
}

function updateStatus() {
  if (gameActive) {
    statusDiv.textContent = 'Trouvez le mot !';
    statusDiv.className = '';
  }
}

// Événement pour recommencer
restartBtn.addEventListener('click', initGame);

// Démarrer une nouvelle partie au chargement
window.onload = initGame;
</script>
